CREATE TABLE `bookings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(50) NOT NULL,
  `customer_id` int(11) DEFAULT NULL,
  `customer_name` varchar(255) NOT NULL,
  `customer_phone` varchar(50) NOT NULL,
  `type` enum('SHARED_RIDE','PRIVATE_RIDE','CARGO','MARKET','CONTRACT','WEDDING','TOUR','HOSPITAL','AIRPORT') NOT NULL,
  `route_id` int(11) DEFAULT NULL,
  `direction` varchar(255) DEFAULT NULL,
  `pickup_address` varchar(500) DEFAULT NULL,
  `dropoff_address` varchar(500) DEFAULT NULL,
  `scheduled_at` datetime DEFAULT NULL,
  `passenger_count` int(11) DEFAULT 1,
  `vehicle_type` varchar(100) DEFAULT NULL,
  `cargo_description` text DEFAULT NULL,
  `market_description` text DEFAULT NULL,
  `note` text DEFAULT NULL,
  `status` enum('NEW','CONTACTED','QUOTED','WAITING_DEPOSIT','DEPOSITED','WAITING_DISPATCH','ASSIGNED','DRIVER_ACCEPTED','IN_PROGRESS','COMPLETED','CANCELLED','NO_SHOW') DEFAULT 'NEW',
  `estimated_total` decimal(12,2) DEFAULT 0.00,
  `final_total` decimal(12,2) DEFAULT 0.00,
  `commission_amount` decimal(12,2) DEFAULT 0.00,
  `pricing_snapshot_json` longtext DEFAULT NULL,
  `payment_receiver` varchar(50) DEFAULT 'DRIVER',
  `source` varchar(50) DEFAULT 'WEBSITE',
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`),
  KEY `customer_id` (`customer_id`),
  KEY `route_id` (`route_id`),
  CONSTRAINT `bookings_ibfk_1` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`),
  CONSTRAINT `bookings_ibfk_2` FOREIGN KEY (`route_id`) REFERENCES `routes` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=302 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
