INSERT INTO `posts` VALUES (1,'Sài Gòn đi Đức Linh bao nhiêu km, mất bao lâu?','sai-gon-di-duc-linh-bao-nhieu-km','Tổng quan thời gian di chuyển, cách đặt xe và lưu ý khi về Đức Linh.','<p>Tuyến Sài Gòn đi Đức Linh phù hợp cho khách về quê cuối tuần, gửi hàng và đi bệnh viện.</p><h2>Có nên đặt xe trước?</h2><p>Nên đặt trước để hệ thống gom khách và sắp tài xế phù hợp.</p>',1,'PUBLISHED','2026-05-25 11:59:42','Sài Gòn đi Đức Linh bao nhiêu km?','Kinh nghiệm đặt xe Sài Gòn đi Đức Linh, thời gian di chuyển và lưu ý.','2026-05-25 11:59:42','2026-05-25 11:59:42'),(2,'Gửi hàng Sài Gòn Đức Linh cần lưu ý gì?','gui-hang-sai-gon-duc-linh-can-luu-y-gi','Lưu ý đóng gói hàng quê, đồ ăn, rau củ, giấy tờ khi gửi xe.','<p>Hàng nên đóng gói kỹ, ghi rõ người gửi/người nhận và số điện thoại.</p>',2,'PUBLISHED','2026-05-25 11:59:42','Gửi hàng Sài Gòn Đức Linh cần lưu ý gì?','Hướng dẫn gửi hàng từ Sài Gòn về Đức Linh và chiều ngược lại.','2026-05-25 11:59:42','2026-05-25 11:59:42');
